#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **graph = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < M; i++) {
            int u, v, c;
            scanf("%d %d %d", &u, &v, &c);
            graph[u - 1][v - 1] = c;
            graph[v - 1][u - 1] = c;
            int mario_score = 0;
            int luigi_score = 0;
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    if (graph[j][k] > 0) {
                        if ((j + k) % 2 == 0) {
                            mario_score += graph[j][k];
                        } else {
                            luigi_score += graph[j][k];
                        }
                    }
                }
            }
            printf("%d\n", mario_score - luigi_score);
        }
        for (int i = 0; i < N; i++) {
            free(graph[i]);
        }
        free(graph);
    }
    return 0;
}

